() => {
  const modal = document.querySelector('.company-profile-modal');
  if (!modal) return 'no modal';

  // Check which tab is active
  const activeTab = modal.querySelector('.cp-tab.active');
  const activeTabText = activeTab ? activeTab.textContent.trim() : 'none';

  // Check the competitors content area
  const compContent = modal.querySelector('.cp-tab-content');
  if (!compContent) return { activeTabText, content: 'no tab content found' };

  const innerHTML = compContent.innerHTML.substring(0, 2000);

  // Check for table
  const table = compContent.querySelector('table');
  const headers = table ? Array.from(table.querySelectorAll('th')).map(th => th.textContent.trim()) : [];

  // Check for rows
  const rows = table ? table.querySelectorAll('tbody tr') : [];
  const rowData = Array.from(rows).map(row => {
    const cells = Array.from(row.querySelectorAll('td'));
    return cells.map(c => c.textContent.trim());
  });

  // Check for loading/error/empty state
  const loading = compContent.querySelector('.cp-loading, .cp-skeleton');
  const error = compContent.querySelector('.cp-error');
  const empty = compContent.querySelector('.cp-empty');

  return {
    activeTabText,
    hasTable: !!table,
    headers,
    rowCount: rows.length,
    rowData: rowData.slice(0, 5),
    hasLoading: !!loading,
    hasError: !!error,
    hasEmpty: !!empty,
    htmlPreview: innerHTML.substring(0, 500)
  };
}

