() => {
  const modal = document.querySelector('.company-profile-modal');
  if (!modal) return 'no modal';

  const activeTab = modal.querySelector('.cp-tab.active');
  const body = modal.querySelector('#company-profile-body');
  if (!body) return { activeTab: activeTab?.textContent, error: 'no body' };

  // Get full HTML of body for inspection
  const html = body.innerHTML;

  // Check for table
  const table = body.querySelector('table');
  const headers = table ? Array.from(table.querySelectorAll('th')).map(th => th.textContent.trim()) : [];

  // Check for rows
  const rows = table ? Array.from(table.querySelectorAll('tbody tr')) : [];
  const rowData = rows.map(row => {
    const cells = Array.from(row.querySelectorAll('td'));
    return cells.map(c => c.textContent.trim());
  });

  // Check for clickable ticker links
  const tickerLinks = body.querySelectorAll('.cp-comp-ticker-link[data-ticker]');
  const tickers = Array.from(tickerLinks).map(l => ({ text: l.textContent.trim(), ticker: l.dataset.ticker }));

  // Check for loading/error/empty
  const loading = body.querySelector('.cp-loading');
  const error = body.querySelector('.cp-error, .cp-comp-error');
  const empty = body.querySelector('.cp-empty, .cp-comp-empty');

  return {
    activeTab: activeTab?.textContent?.trim(),
    hasTable: !!table,
    headers,
    rowCount: rows.length,
    rowData,
    tickers,
    hasLoading: !!loading,
    hasError: !!error,
    errorText: error?.textContent?.trim(),
    hasEmpty: !!empty,
    htmlLength: html.length,
    htmlPreview: html.substring(0, 800)
  };
}

